  ('generalpolice-f3743df6-moex-00098', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '依司法院大法官解釋，有關人民工作權、財產權，下列敘述何者錯誤？', '["基於憲法工作權之保障，人民得自由選擇從事特定職業", "航空人員之技能、體格或性行，經檢查不合標準時，得限制、暫停或終止其執業，並未侵害其工 作權", "公務員服務法規定，公務員於其離職後3年內，不得擔任與其離職前5年內之職務直接相關之營 利事業董事，侵害其工作權", "道路交通管理處罰條例規定，曾犯故意殺人罪，經判決罪刑確定者，不准辦理營業小客車駕駛人執 業登記，並未侵害其工作權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
